SELECT 
FROM medicine m
INNER JOIN medicine_category c ON m.category_id = c.id
LEFT JOIN supplier s ON m.supplier_id = s.id


        AND (
            m.medicine_name LIKE CONCAT('%', #{query.keyword}, '%')
            OR m.medicine_code LIKE CONCAT('%', #{query.keyword}, '%')
        )


        AND m.category_id = #{query.categoryId}


        AND m.supplier_id = #{query.supplierId}


        AND m.is_controlled = #{query.isControlled}


        AND m.status = #{query.status}


ORDER BY m.id DESC

